+#[derive(Debug, Clone)]
+struct SimMetrics {
+    applies: usize,
+    forced: usize,
+    decisions: usize,
+    mean_coalesce_ms: f64,
+    p95_coalesce_ms: f64,
+    max_coalesce_ms: f64,
